    pendu: async (sock, from, msg) => {
        const mots = ["HAITI","TECHNOLOGIE","INNOVATION","WHATSAPP","ORDINATEUR","INTERNET","OTECH","JAVASCRIPT","ANDROID","TERMUX","CYBERPUNK","BLOCKCHAIN"];
        const mot = rand(mots);
        penduSessions.set(`pendu_${from}`, { mot, trouve: Array(mot.length).fill("_"), lettres: [], erreurs: 0, max: 6 });
        const s = penduSessions.get(`pendu_${from}`);
        await reply(sock, from, `${SKULL} *JEU DU PENDU*\n\nMot: *${s.trouve.join(" ")}*\nLettres: ${mot.length}\nErreurs: 0/${s.max}\n\n_Tape .lettre X_`, msg);
    },

    lettre: async (sock, from, msg, args) => {
        const key = `pendu_${from}`;
        const s = penduSessions.get(key);
        if (!s) return reply(sock, from, "❌ Pas de partie. Tape .pendu", msg);
        const lettre = args[0]?.toUpperCase();
        if (!lettre || lettre.length !== 1) return reply(sock, from, "❌ Usage: .lettre A", msg);
        if (s.lettres.includes(lettre)) return reply(sock, from, `⚠️ Lettre *${lettre}* deja essayee!`, msg);
        s.lettres.push(lettre);
        if (s.mot.includes(lettre)) {
            for (let i = 0; i < s.mot.length; i++) if (s.mot[i] === lettre) s.trouve[i] = lettre;
        } else { s.erreurs++; }
        const art = ["😊","😐","😟","😨","😰","😱","💀"];
        if (!s.trouve.includes("_")) {
            penduSessions.delete(key);
            addCoins(msg.key.participant || from, s.mot.length * 10);
            return reply(sock, from, `🎉 *GAGNE!* Mot: *${s.mot}*\n💰 +${s.mot.length*10} coins!`, msg);
        }
        if (s.erreurs >= s.max) {
            penduSessions.delete(key);
            return reply(sock, from, `${SKULL} *PERDU!* Le mot etait: *${s.mot}*`, msg);
        }
        await reply(sock, from, `${art[s.erreurs]} *PENDU*\n\nMot: *${s.trouve.join(" ")}*\nEssayees: ${s.lettres.join(", ")}\nErreurs: ${s.erreurs}/${s.max}`, msg);
    },

