    // NOTE — sauvegarder une note ──────────────
    note: async (sock, from, msg, args, sender) => {
        const texte = args.join(" ");
        if (!texte.trim()) return reply(sock, from, "❌ Usage: .note Ton texte ici", msg);
        if (!notesMap.has(sender)) notesMap.set(sender, []);
        const notes = notesMap.get(sender);
        notes.push({ text: texte, date: new Date().toLocaleString("fr-FR") });
        await reply(sock, from, `${CYBER} Note ${notes.length} sauvegardee!\n_${texte}_`, msg);
    },

    notes: async (sock, from, msg, args, sender) => {
        const notes = notesMap.get(sender) || [];
        if (!notes.length) return reply(sock, from, "❌ Aucune note. Tape .note texte", msg);
        let text = `${CHIP} *Tes Notes (${notes.length}):*\n\n`;
        notes.forEach((n, i) => text += `*${i+1}.* ${n.text}\n_${n.date}_\n\n`);
        await reply(sock, from, text, msg);
    },

    supp: async (sock, from, msg, args, sender) => {
        const idx = parseInt(args[0]) - 1;
        const notes = notesMap.get(sender) || [];
        if (isNaN(idx) || idx < 0 || idx >= notes.length) return reply(sock, from, `❌ Usage: .supp [numero] (1-${notes.length})`, msg);
        const removed = notes.splice(idx, 1)[0];
        await reply(sock, from, `${BLADE} Note supprimee:\n_${removed.text}_`, msg);
    },

